import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"识别、回忆、认知负荷与信息分组","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/principles/03-recognition-cognitive-load-grouping.md","filePath":"03-interaction-design/notes/principles/03-recognition-cognitive-load-grouping.md","lastUpdated":1784248569000}'),n={name:"03-interaction-design/notes/principles/03-recognition-cognitive-load-grouping.md"};function r(s,a,d,o,h,p){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="识别、回忆、认知负荷与信息分组" tabindex="-1">识别、回忆、认知负荷与信息分组 <a class="header-anchor" href="#识别、回忆、认知负荷与信息分组" aria-label="Permalink to &quot;识别、回忆、认知负荷与信息分组&quot;">​</a></h1><p>识别与回忆描述用户取得信息的两种方式；认知负荷描述任务占用注意、工作记忆和推理资源的程度；信息分组通过结构、名称、顺序和视觉关系帮助用户定位与处理内容。设计目标不是消除思考，而是减少与任务无关的记忆、搜索和转换。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>定义</th><th>界面例子</th><th>不能推导出的结论</th></tr></thead><tbody><tr><td>识别</td><td>从当前可见选项或线索中判断目标</td><td>从最近项目列表选择项目</td><td>所有选项都应永久展示</td></tr><tr><td>回忆</td><td>在缺少直接线索时从记忆中提取信息</td><td>输入不常用命令或项目 ID</td><td>回忆一定不可用</td></tr><tr><td>认知负荷</td><td>完成任务时用于理解、记忆、判断和控制的资源需求</td><td>记住前页数据再跨字段计算</td><td>可用单一数值准确测量全部认知过程</td></tr><tr><td>信息分组</td><td>按任务相关关系组织元素</td><td>按“账户、通知、安全”分组设置</td><td>视觉接近就一定属于同一语义组</td></tr></tbody></table><p>熟练用户可能通过回忆快速执行命令，初次用户则需要可见选项。好的系统可以同时提供导航、搜索、最近记录与快捷命令，而不是在“识别或回忆”之间二选一。</p><h2 id="工作机制" tabindex="-1">工作机制 <a class="header-anchor" href="#工作机制" aria-label="Permalink to &quot;工作机制&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G[&quot;任务目标&quot;] --&gt; C[&quot;从当前界面获取线索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; R[&quot;识别对象与操作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; D[&quot;作出判断&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; A[&quot;执行动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; F[&quot;反馈更新当前线索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M[&quot;需要记住的信息&quot;] --&gt; D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>界面线索越准确，用户越少需要在页面之间记忆临时信息。但增加大量同时可见的选项也会提高搜索和判断成本。设计要保留当前决策所需信息，把次要内容按任务关系分组或按需展开。</p><h2 id="识别与回忆" tabindex="-1">识别与回忆 <a class="header-anchor" href="#识别与回忆" aria-label="Permalink to &quot;识别与回忆&quot;">​</a></h2><h3 id="适合识别的内容" tabindex="-1">适合识别的内容 <a class="header-anchor" href="#适合识别的内容" aria-label="Permalink to &quot;适合识别的内容&quot;">​</a></h3><ul><li>低频使用的对象、命令和格式；</li><li>难以准确记忆的 ID、日期、路径和规则；</li><li>错误成本高、需要核对的目标；</li><li>状态依赖明显、可用项随权限变化的操作。</li></ul><p>常用机制包括最近项目、自动完成、历史记录、可见标签、菜单、示例格式和当前状态。识别线索必须可区分：只显示多个同名“设计稿”而没有项目、所有者或时间，仍然无法正确识别。</p><h3 id="回忆仍有价值的情况" tabindex="-1">回忆仍有价值的情况 <a class="header-anchor" href="#回忆仍有价值的情况" aria-label="Permalink to &quot;回忆仍有价值的情况&quot;">​</a></h3><ul><li>专业用户反复执行稳定命令；</li><li>快捷键能显著提高重复任务效率；</li><li>用户本来就持有并需要输入的安全信息；</li><li>搜索表达比浏览大量选项更快。</li></ul><p>回忆路径应是加速器，不应成为唯一入口。快捷键需要可发现、可关闭冲突并提供等价可见操作；命令面板应支持搜索、最近使用与错误容忍。</p><h3 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h3><p>不要为减少回忆而暴露敏感凭据。密码管理器、平台自动填充和安全认证流程可以减少重复输入，但产品不能在页面明文显示密码或密钥。</p><h2 id="认知负荷的来源" tabindex="-1">认知负荷的来源 <a class="header-anchor" href="#认知负荷的来源" aria-label="Permalink to &quot;认知负荷的来源&quot;">​</a></h2><p>“认知负荷”在交互分析中可拆成可观察的任务需求，不应只用作“界面看起来复杂”的评价。</p><h3 id="记忆负担" tabindex="-1">记忆负担 <a class="header-anchor" href="#记忆负担" aria-label="Permalink to &quot;记忆负担&quot;">​</a></h3><p>用户必须记住前一步信息、隐藏规则、对象位置或未保存修改。修正方式包括保留摘要、显示当前选择、提供历史和让结果可重新查看。</p><h3 id="搜索负担" tabindex="-1">搜索负担 <a class="header-anchor" href="#搜索负担" aria-label="Permalink to &quot;搜索负担&quot;">​</a></h3><p>用户在大量、相似或无序内容中寻找目标。应提高标识差异、提供任务相关排序与筛选，并建立清晰标题和分组。</p><h3 id="决策负担" tabindex="-1">决策负担 <a class="header-anchor" href="#决策负担" aria-label="Permalink to &quot;决策负担&quot;">​</a></h3><p>用户需要比较许多难以区分的方案或理解不明确后果。应展示比较维度、默认值、推荐依据和结果差异；不能替用户隐藏必要风险。</p><h3 id="转换负担" tabindex="-1">转换负担 <a class="header-anchor" href="#转换负担" aria-label="Permalink to &quot;转换负担&quot;">​</a></h3><p>用户在不同单位、术语、页面或数据表示之间转换。例如列表显示“剩余 2 天”，编辑页只显示 UTC 时间戳。应保持单位和对象一致，必要转换由系统完成并可核对。</p><h3 id="控制负担" tabindex="-1">控制负担 <a class="header-anchor" href="#控制负担" aria-label="Permalink to &quot;控制负担&quot;">​</a></h3><p>用户需要精确指针操作、记忆复杂快捷键或在不稳定布局中追踪焦点。应提供足够目标、稳定布局、标准键盘模型和可见焦点。</p><h2 id="信息分组" tabindex="-1">信息分组 <a class="header-anchor" href="#信息分组" aria-label="Permalink to &quot;信息分组&quot;">​</a></h2><h3 id="语义优先" tabindex="-1">语义优先 <a class="header-anchor" href="#语义优先" aria-label="Permalink to &quot;语义优先&quot;">​</a></h3><p>先按用户任务、对象关系和使用顺序分组，再用视觉表达。视觉分组方式包括：</p><ul><li>标题与语义区域；</li><li>邻近与一致间距；</li><li>边界、背景或分隔；</li><li>对齐和重复结构；</li><li>顺序与层级。</li></ul><p>视觉邻近会暗示关系，因此相关字段间距应小于组与组之间的间距；但语义不能只靠空白表达，代码结构和标题也应让辅助技术识别关系。</p><h3 id="分组粒度" tabindex="-1">分组粒度 <a class="header-anchor" href="#分组粒度" aria-label="Permalink to &quot;分组粒度&quot;">​</a></h3><p>组过大会隐藏内部层次，组过小会产生过多标题和边界。判断粒度时检查：</p><ul><li>组内元素是否服务同一子任务？</li><li>用户是否需要一起比较或一起提交？</li><li>组名能否准确预测内容？</li><li>错误和帮助是否能定位到具体组？</li></ul><h3 id="顺序" tabindex="-1">顺序 <a class="header-anchor" href="#顺序" aria-label="Permalink to &quot;顺序&quot;">​</a></h3><p>表单通常按用户取得信息和完成任务的顺序排列；设置可以按对象或影响范围；结果列表按主要比较任务排序。视觉顺序、DOM 顺序和键盘顺序应保持意义一致，不能仅用 CSS 把元素视觉重排。</p><h2 id="完整案例-配置项目通知" tabindex="-1">完整案例：配置项目通知 <a class="header-anchor" href="#完整案例-配置项目通知" aria-label="Permalink to &quot;完整案例：配置项目通知&quot;">​</a></h2><h3 id="输入证据" tabindex="-1">输入证据 <a class="header-anchor" href="#输入证据" aria-label="Permalink to &quot;输入证据&quot;">​</a></h3><p>现有设置页有 18 个开关，按开发模块命名并单列排列。公开帮助记录显示用户常问：哪些通知会发邮件、关闭“动态通知”是否影响被点名提醒。行为日志显示用户频繁来回切换同一组开关，但日志不能单独解释原因。</p><p>当前字段示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>activity_enabled</span></span>
<span class="line"><span>mention_enabled</span></span>
<span class="line"><span>assignment_enabled</span></span>
<span class="line"><span>digest_enabled</span></span>
<span class="line"><span>email_enabled</span></span>
<span class="line"><span>push_enabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="分析过程" tabindex="-1">分析过程 <a class="header-anchor" href="#分析过程" aria-label="Permalink to &quot;分析过程&quot;">​</a></h3><ol><li>用户目标是控制“什么事件通过什么渠道通知我”，不是理解内部字段名。</li><li>需要同时比较事件与渠道，因此单列混排会产生转换和记忆负担。</li><li>“被点名”和“被分配任务”属于高相关事件，不应被笼统“动态通知”隐藏。</li><li>邮件和推送是渠道，事件与渠道是两个维度；需明确不支持的组合。</li><li>默认值与组织强制规则会限制选择，必须在控件附近解释。</li></ol><h3 id="输出结构" tabindex="-1">输出结构 <a class="header-anchor" href="#输出结构" aria-label="Permalink to &quot;输出结构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>站内</th><th>邮件</th><th>推送</th></tr></thead><tbody><tr><td>被点名</td><td>开</td><td>开</td><td>开</td></tr><tr><td>被分配任务</td><td>开</td><td>开</td><td>开</td></tr><tr><td>项目状态变化</td><td>开</td><td>关</td><td>关</td></tr><tr><td>每日摘要</td><td>不适用</td><td>开</td><td>不适用</td></tr></tbody></table><p>分组标题使用“需要立即处理”和“项目动态”，每个事件保留可见名称与简短说明。矩阵只在列数和屏幕宽度允许时使用；窄屏改为按事件分组的控件，DOM 顺序保持“事件 → 渠道”。</p><h3 id="状态与交互" tabindex="-1">状态与交互 <a class="header-anchor" href="#状态与交互" aria-label="Permalink to &quot;状态与交互&quot;">​</a></h3><ul><li>初始加载完成前不显示错误默认值；使用加载状态或禁用并说明正在读取。</li><li>组织强制开启的“安全提醒”显示只读状态和规则来源，不伪装成可切换。</li><li>保存采用显式按钮时，页面持续显示未保存状态；离开前处理未保存修改。</li><li>保存成功后显示持久的当前值，并用非阻断状态消息宣布。</li><li>保存失败保留修改，指出失败范围；部分成功时逐项显示权威结果。</li><li>每个开关有可访问名称，名称包含事件和渠道，避免读屏只听到多个“开启”。</li></ul><h3 id="可观察验证" tabindex="-1">可观察验证 <a class="header-anchor" href="#可观察验证" aria-label="Permalink to &quot;可观察验证&quot;">​</a></h3><p>给测试者三个任务：关闭项目状态变化邮件、保留被点名推送、确认安全提醒能否关闭。记录首次操作是否正确、查找路径、错误和最终保存状态。</p><p>通过条件：三项任务均无需记忆内部名称；测试者能在操作前预测影响渠道；刷新后值与确认结果一致。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若矩阵在 200% 缩放时产生双向滚动并失去行列标题，则不能继续压缩字体。改用按事件分组的垂直结构，并在每组重复渠道标签。若组织策略在用户保存期间改变，系统返回冲突，展示强制值并保留仍可修改的选择。</p><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>写出任务中用户需要识别、回忆、比较和转换的信息。</li><li>收集行为、帮助、错误和现有结构证据；未知原因标为假设。</li><li>为低频、易错和高风险信息提供可靠识别线索。</li><li>按对象关系或任务顺序建立语义分组，并为每组命名。</li><li>用间距、标题、边界和对齐表达分组，保持 DOM 与视觉顺序一致。</li><li>保留专业用户的搜索、快捷键或批量路径，但提供可见等价操作。</li><li>加入真实长内容、空值、权限、加载、错误和窄屏状态。</li><li>用查找、比较、配置和恢复任务验证，而不是只询问主观简洁度。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>以“减少认知负荷”为理由隐藏完成任务所需的信息。</li><li>把所有选项都展示出来，误以为识别一定优于回忆。</li><li>只通过颜色或空白分组，没有标题和程序语义。</li><li>按数据库字段、团队结构或组件类型分组，而不是用户任务。</li><li>视觉顺序与 DOM、键盘顺序不同。</li><li>为熟练用户优化快捷键，却没有可发现的普通路径。</li><li>用单次操作时间解释全部认知负荷，忽略错误与学习效果。</li><li>自动填充敏感数据，却没有安全与授权边界。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>让测试者在执行前指出目标、当前状态和预期结果。</li><li>记录是否需要返回前页、抄写数据或记忆隐藏规则。</li><li>用真实数据测试同名对象、长文本、大量选项和缺失值。</li><li>仅用键盘检查分组顺序、焦点与快捷路径。</li><li>用屏幕阅读器确认标题、fieldset/legend、表格标题和控件名称。</li><li>在窄屏和 200% 放大下检查分组仍能保持关系，避免双向滚动。</li><li>刷新、失败和权限变化后，确认当前选择和结果可重新识别。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>重构一个包含至少 15 项的账户设置页。</p><p>完成时应满足：</p><ul><li>列出每项任务需要识别、回忆、比较和转换的内容；</li><li>分组依据来自任务或对象关系，并有可预测组名；</li><li>至少为三个低频操作提供识别线索；</li><li>同时支持初次用户的可见路径与熟练用户的加速路径；</li><li>覆盖加载、未保存、成功、失败、只读和权限状态；</li><li>视觉、DOM 和键盘顺序保持意义一致；</li><li>使用具体任务验证查找、预测、保存和恢复，并记录通过条件。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/tutorials/page-structure/" target="_blank" rel="noreferrer">W3C WAI：Page Structure Tutorial</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/focus-order.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 2.4.3 Focus Order</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/consistent-identification.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 3.2.4 Consistent Identification</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/tutorials/forms/" target="_blank" rel="noreferrer">W3C WAI：Forms Tutorial</a>（访问日期：2026-07-17）</li></ul>`,68)])])}const b=i(n,[["render",r]]);export{u as __pageData,b as default};
